mapper.select:


    1 = 1
    and e.event_id = #{eventId}
    and e.asset_id = #{assetId}
    and a.asset_code like concat('%', #{assetCode}, '%')
    and a.asset_name like concat('%', #{assetName}, '%')
    and e.event_type = #{eventType}
    and e.source_order_type = #{sourceOrderType}

        and (
            o.order_no like concat('%', #{sourceOrderNo}, '%')
            or t.task_no like concat('%', #{sourceOrderNo}, '%')
        )

    and e.operator_user_id = #{operatorUserId}

        and (
            operator_user.nick_name like concat('%', #{operatorUserName}, '%')
            or operator_user.user_name like concat('%', #{operatorUserName}, '%')
        )


        and date_format(e.operate_time, '%Y-%m-%d') >= #{beginOperateTime}


        and date_format(e.operate_time, '%Y-%m-%d') <= #{endOperateTime}

    ${params.dataScope}

order by e.operate_time desc, e.event_id desc

    limit #{limitSize}


where e.asset_id = #{assetId}
order by e.operate_time desc, e.event_id desc
limit #{limit}

